queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTopics ?child ; p:hasBank_Training ?parent . } GROUP BY ?child }
  ?child p:value ?value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Bank_Training } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?training_id ?value WHERE {
  ?bank_training_topics a :Bank_Training_Topics .
  ?topics a :Topics .
  ?bank_training_topics p:hasTopics ?topics .
  ?bank_training a :Bank_Training .
  ?bank_training_topics p:hasBank_Training ?bank_training .
  ?bank_training p:training_id ?training_id .
  ?topics p:value ?value .
} }
  collective: { SELECT ?value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTopics ?child ; p:hasBank_Training ?parent . } GROUP BY ?child }
  ?child p:value ?value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Bank_Training } }
  FILTER(?nf = ?total)
} }
}
